def build_tree(depth, breadth):
    if depth == 0: return 'leaf'
    return {f'child_{i}': build_tree(depth - 1, breadth) for i in range(breadth)}

tree = build_tree(6, 4) # 4^6 = 4096 leaves

def count_leaves(node):
    if isinstance(node, str): return 1
    return sum(count_leaves(child) for child in node.values())

print(f'Total leaves: {count_leaves(tree)}')
print(f'Keys at root: {len(tree)}')

